import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []

all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    proj, tfm, pkg_id = k
    if k in b and k in a:
        b_req, b_res = b[k]
        a_req, a_res = a[k]
        if b_res != a_res:
            changes.append((proj, tfm, pkg_id, b_res, a_res, 'Aligned to highest version'))
        else:
            unchanged.append((proj, tfm, pkg_id, a_res))
    elif k in b and k not in a:
        b_req, b_res = b[k]
        changes.append((proj, tfm, pkg_id, b_res, 'REMOVED', 'Removed'))
    else:
        a_req, a_res = a[k]
        changes.append((proj, tfm, pkg_id, 'N/A', a_res, 'Added'))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]:15s} {c[1]:8s} {c[2]:50s} {c[3]:10s} -> {c[4]:10s}  ({c[5]})')
else:
    print('None')

print()
print(f'=== UNCHANGED ({len(unchanged)} packages) ===')
for u in unchanged:
    print(f'{u[0]:15s} {u[1]:8s} {u[2]:50s} {u[3]}')
"

